#!/usr/bin/env node
// Minimal local-search MCP stdio handshake stub. Operator extends with
// their own RSS feeds via .maddu/mcp/local-search/feeds.json.
//
// On `initialize`, returns protocolVersion. On any other method, echoes
// the curated feed URLs from feeds.json. No external API calls.
import { readFile } from 'node:fs/promises';
import { join, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const here = dirname(fileURLToPath(import.meta.url));
const feedsPath = join(here, 'feeds.json');
let feeds = [];
try { feeds = JSON.parse(await readFile(feedsPath, 'utf8')); } catch {}

process.stdin.setEncoding('utf8');
let buf = '';
process.stdin.on('data', (chunk) => {
  buf += chunk;
  let idx;
  while ((idx = buf.indexOf('\n')) >= 0) {
    const line = buf.slice(0, idx);
    buf = buf.slice(idx + 1);
    if (!line.trim()) continue;
    let msg;
    try { msg = JSON.parse(line); } catch { continue; }
    if (msg.method === 'initialize') {
      process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result: { protocolVersion: '0.1.0', capabilities: {}, serverInfo: { name: 'local-search', version: '0.1.0' } } }) + '\n');
      continue;
    }
    process.stdout.write(JSON.stringify({ jsonrpc: '2.0', id: msg.id, result: { feeds } }) + '\n');
  }
});
